// Auto-validation and enhancement of document metadata
const documents = $input.all();

const processedDocs = documents.map(item => {
  const doc = item.json;
  const meta = doc.metadata;
  const content = doc.pageContent.toLowerCase();

  // Auto-suggest additional keywords based on content analysis
  const autoKeywords = [];

  // Technical terms detection
  const technicalTerms = [
    'TDUID', 'tdconv', 'trsdk', 'TDConversion', 'dataLayer',
    'CNAME', 'DNS', 'subdomain', 'GTM', 'Tag Manager',
    'ordervalue', 'transactionId', 'currency', 'voucher',
    'XML', 'CSV', 'product feed', 'SKU', 'EAN'
  ];

  technicalTerms.forEach(term => {
    if (content.includes(term.toLowerCase())) {
      autoKeywords.push(term);
    }
  });

  // Merge auto-detected keywords with existing ones (remove duplicates)
  const allKeywords = [...new Set([...meta.keywords, ...autoKeywords])];

  // Add search_text field for better full-text matching
  const searchText = [
    meta.category,
    meta.topic,
    meta.subtopic,
    ...allKeywords,
    doc.pageContent.substring(0, 200) // First 200 chars
  ].join(' ');

  return {
    json: {
      ...doc,
      metadata: {
        ...meta,
        keywords: allKeywords,
        search_text: searchText,
        last_updated: new Date().toISOString()
      }
    }
  };
});

return processedDocs;
